def log_event(event: dict):
    event = dict(event)
    event["ts"] = datetime.datetime.utcnow().isoformat()
    try:
        with open(LOG_PATH, "a", encoding="utf-8") as f:
            f.write(json.dumps(event) + "\n")
    except Exception:
        pass


